using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the discriminator property from "Discriminator" to "$type".
            // Preserve the old name so existing 500K documents remain readable and
            // direct SQL queries referencing c.Discriminator keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id format from "EntityType|KeyValue" to just "KeyValue".
            // Preserve the old format so existing documents are still addressable.
            entity.Property(p => p.Id).HasJsonPropertyName("id");
            entity.HasKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // EF Core 9 removed HasIndex support for Cosmos (Cosmos has no secondary indexes).
        // The HasIndex call from EF 8 has been removed above.
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; }
}

/// <summary>
/// Reproduces the EF Core 8 Cosmos id format: "EntityType|KeyValue"
/// so that existing documents written with that convention remain accessible.
/// </summary>
using Microsoft.EntityFrameworkCore.ValueGeneration;
using Microsoft.EntityFrameworkCore.ChangeTracking;

class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var entityType = entry.Metadata.ShortName();
        var id = entry.Property("Id").CurrentValue;
        return $"{entityType}|{id}";
    }
}

