class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we explicitly kept "Discriminator"
        // as the discriminator property name in OnModelCreating.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos provider removed synchronous APIs (ToList, First, Single, etc.).
        // All queries must use their async counterparts.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

